package hellfirepvp.astralsorcery.datagen.data.recipes.altar;

import hellfirepvp.astralsorcery.common.crafting.recipe.altar.builtin.NBTCopyRecipe;
import net.minecraft.world.level.material.Fluid;
import hellfirepvp.astralsorcery.common.lib.FluidsAS;
import hellfirepvp.astralsorcery.common.lib.AltarRecipeEffectsAS;
import net.minecraft.tags.ItemTags;
import net.minecraft.world.item.Item;
import net.minecraft.tags.TagKey;
import net.minecraftforge.common.Tags;
import hellfirepvp.astralsorcery.common.item.ItemResonator;
import net.minecraft.world.item.ItemStack;
import hellfirepvp.astralsorcery.common.util.NameUtil;
import net.minecraft.world.level.ItemLike;
import hellfirepvp.astralsorcery.common.lib.ItemsAS;
import hellfirepvp.astralsorcery.common.lib.TagsAS;
import net.minecraft.world.item.crafting.Ingredient;
import hellfirepvp.astralsorcery.common.crafting.helper.ingredient.CrystalIngredient;
import hellfirepvp.astralsorcery.common.crafting.recipe.altar.AltarRecipeGrid;

import hellfirepvp.astralsorcery.common.block.tile.altar.AltarType;
import hellfirepvp.astralsorcery.common.lib.BlocksAS;
import hellfirepvp.astralsorcery.common.crafting.builder.SimpleAltarRecipeBuilder;
import hellfirepvp.astralsorcery.common.crafting.recipe.altar.AltarRecipeTypeHandler;
import net.minecraft.data.IFinishedRecipe;
import java.util.function.Consumer;

public class AttunementAltarRecipeProvider
{
    public static void registerAltarRecipes(final Consumer<IFinishedRecipe> registrar) {
        registerRecipes(registrar);
    }
    
    private static void registerRecipes(final Consumer<IFinishedRecipe> registrar) {
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.ALTAR_UPGRADE_CONSTELLATION).createRecipe((Object<?>)BlocksAS.ALTAR_CONSTELLATION, AltarType.ATTUNEMENT).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("S   S").patternLine(" A A ").patternLine(" MCM ").patternLine(" PIP ").patternLine("M   M").key('C', new CrystalIngredient(false, false)).key('S', TagsAS.Items.DUSTS_STARDUST).key('I', TagsAS.Items.INGOTS_STARMETAL).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('M', (ItemLike)BlocksAS.MARBLE_CHISELED).key('P', (ItemLike)BlocksAS.MARBLE_PILLAR)).addOutput((ItemLike)BlocksAS.ALTAR_CONSTELLATION).build(registrar);
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.NBT_COPY).createRecipe(NameUtil.suffixPath(ItemsAS.RESONATOR.getRegistryName(), "_upgrade_domic"), AltarType.ATTUNEMENT).modify(recipe -> recipe.addNBTCopyMatchIngredient((ItemLike)ItemsAS.RESONATOR)).setStarlightRequirement(0.4f).setInputs(AltarRecipeGrid.builder().patternLine("I   I").patternLine(" I I ").patternLine(" GRG ").patternLine(" S S ").patternLine("S   S").key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER).key('G', (ItemLike)ItemsAS.GLASS_LENS).key('S', TagsAS.Items.DUSTS_STARDUST).key('R', (ItemLike)ItemsAS.RESONATOR)).addOutput(ItemResonator.setCurrentUpgradeUnsafe(ItemResonator.setUpgradeUnlocked(new ItemStack((ItemLike)ItemsAS.RESONATOR), ItemResonator.ResonatorUpgrade.STARLIGHT, ItemResonator.ResonatorUpgrade.AREA_SIZE), ItemResonator.ResonatorUpgrade.AREA_SIZE)).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)BlocksAS.TELESCOPE, AltarType.ATTUNEMENT).setStarlightRequirement(0.4f).setInputs(AltarRecipeGrid.builder().patternLine(" T ").patternLine("GPG").patternLine("SSS").key('T', (ItemLike)ItemsAS.HAND_TELESCOPE).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('P', (ITag.INamedTag<Item>)ItemTags.field_199905_b).key('S', (ITag.INamedTag<Item>)Tags.Items.RODS_WOODEN)).addOutput((ItemLike)BlocksAS.TELESCOPE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)BlocksAS.GATEWAY, AltarType.ATTUNEMENT).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("S   S").patternLine("  N  ").patternLine(" LCL ").patternLine(" RSR ").patternLine("G   G").key('S', TagsAS.Items.DUSTS_STARDUST).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('R', (ItemLike)BlocksAS.MARBLE_RUNED).key('C', new CrystalIngredient(false, false)).key('L', (ItemLike)ItemsAS.GLASS_LENS).key('N', (ItemLike)ItemsAS.NOCTURNAL_POWDER)).addOutput((ItemLike)BlocksAS.GATEWAY).addAltarEffect(AltarRecipeEffectsAS.GATEWAY_EDGE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)BlocksAS.RITUAL_PEDESTAL, AltarType.ATTUNEMENT).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("G   G").patternLine(" MCM ").patternLine(" PLP ").patternLine(" RRR ").patternLine("P   P").key('C', new CrystalIngredient(false, false)).key('L', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('M', (ItemLike)BlocksAS.MARBLE_CHISELED).key('P', (ItemLike)BlocksAS.MARBLE_PILLAR).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)BlocksAS.RITUAL_PEDESTAL).build(registrar);
        SimpleAltarRecipeBuilder.ofType(AltarRecipeTypeHandler.CRYSTAL_SET_COUNT).createRecipe((Object<?>)BlocksAS.LENS, AltarType.ATTUNEMENT).setStarlightRequirement(0.3f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine(" ALA ").patternLine(" LCL ").patternLine(" WGW ").patternLine("R   R").key('C', new CrystalIngredient(false, false)).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('L', (ItemLike)ItemsAS.GLASS_LENS).key('W', (ItemLike)BlocksAS.INFUSED_WOOD_ENGRAVED).key('G', (ITag.INamedTag<Item>)Tags.Items.INGOTS_GOLD).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)BlocksAS.LENS).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)BlocksAS.ATTUNEMENT_ALTAR, AltarType.ATTUNEMENT).setStarlightRequirement(0.8f).setInputs(AltarRecipeGrid.builder().patternLine("A   A").patternLine("  C  ").patternLine(" M M ").patternLine(" RSR ").patternLine("R   R").key('C', new CrystalIngredient(false, false)).key('A', (ItemLike)ItemsAS.AQUAMARINE).key('M', TagsAS.Items.INGOTS_STARMETAL).key('S', (ItemLike)BlocksAS.SPECTRAL_RELAY).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)BlocksAS.ATTUNEMENT_ALTAR).addAltarEffect(AltarRecipeEffectsAS.ALTAR_DEFAULT_SPARKLE).addAltarEffect(AltarRecipeEffectsAS.ALTAR_DEFAULT_LIGHTBEAM).addAltarEffect(AltarRecipeEffectsAS.PILLAR_SPARKLE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.PERK_SEAL, AltarType.ATTUNEMENT).setStarlightRequirement(0.1f).setInputs(AltarRecipeGrid.builder().patternLine("N   N").patternLine("     ").patternLine(" SLS ").patternLine("     ").patternLine("N   N").key('N', (ItemLike)ItemsAS.NOCTURNAL_POWDER).key('S', TagsAS.Items.DUSTS_STARDUST).key('L', (ItemLike)ItemsAS.GLASS_LENS)).addOutput(new ItemStack((ItemLike)ItemsAS.PERK_SEAL, 4)).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.KNOWLEDGE_SHARE, AltarType.ATTUNEMENT).setStarlightRequirement(0.7f).setInputs(AltarRecipeGrid.builder().patternLine("I   I").patternLine("  F  ").patternLine(" SPS ").patternLine("  B  ").patternLine("I   I").key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER).key('F', (ITag.INamedTag<Item>)Tags.Items.FEATHERS).key('S', TagsAS.Items.DUSTS_STARDUST).key('P', (ItemLike)ItemsAS.PARCHMENT).key('B', (ITag.INamedTag<Item>)Tags.Items.DYES_BLACK)).addOutput((ItemLike)ItemsAS.KNOWLEDGE_SHARE).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.GRAPPLE_WAND, AltarType.ATTUNEMENT).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  SB ").patternLine(" BR  ").patternLine(" R   ").patternLine("R    ").key('S', TagsAS.Items.DUSTS_STARDUST).key('B', (ITag.INamedTag<Item>)Tags.Items.DYES_BLUE).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)ItemsAS.GRAPPLE_WAND).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.ARCHITECT_WAND, AltarType.ATTUNEMENT).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  SP ").patternLine(" PRS ").patternLine(" R   ").patternLine("R    ").key('S', TagsAS.Items.DUSTS_STARDUST).key('P', (ITag.INamedTag<Item>)Tags.Items.DYES_PURPLE).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)ItemsAS.ARCHITECT_WAND).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.EXCHANGE_WAND, AltarType.ATTUNEMENT).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  SD ").patternLine(" DR  ").patternLine(" R   ").patternLine("R    ").key('S', TagsAS.Items.DUSTS_STARDUST).key('D', (ITag.INamedTag<Item>)Tags.Items.GEMS_DIAMOND).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)ItemsAS.EXCHANGE_WAND).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.BLINK_WAND, AltarType.ATTUNEMENT).setStarlightRequirement(0.6f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  E  ").patternLine(" ERS ").patternLine(" RD  ").patternLine("R    ").key('S', TagsAS.Items.DUSTS_STARDUST).key('D', (ITag.INamedTag<Item>)Tags.Items.GEMS_DIAMOND).key('E', (ITag.INamedTag<Item>)Tags.Items.ENDER_PEARLS).key('R', (ItemLike)BlocksAS.MARBLE_RUNED)).addOutput((ItemLike)ItemsAS.BLINK_WAND).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.LINKING_TOOL, AltarType.ATTUNEMENT).setStarlightRequirement(0.3f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine(" SA  ").patternLine(" SCA ").patternLine(" LSS ").patternLine("L    ").key('C', new CrystalIngredient(false, false)).key('S', (ITag.INamedTag<Item>)Tags.Items.RODS_WOODEN).key('L', (ITag.INamedTag<Item>)ItemTags.field_200038_h).key('A', (ItemLike)ItemsAS.AQUAMARINE)).addOutput((ItemLike)ItemsAS.LINKING_TOOL).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.SHIFTING_STAR, AltarType.ATTUNEMENT).setStarlightRequirement(0.8f).setInputs(AltarRecipeGrid.builder().patternLine("A   A").patternLine(" S S ").patternLine(" ILI ").patternLine(" S S ").patternLine("A   A").key('L', (Fluid)FluidsAS.LIQUID_STARLIGHT_SOURCE).key('I', (ItemLike)ItemsAS.ILLUMINATION_POWDER).key('S', TagsAS.Items.DUSTS_STARDUST).key('A', (ItemLike)ItemsAS.AQUAMARINE)).addOutput((ItemLike)ItemsAS.SHIFTING_STAR).build(registrar);
        SimpleAltarRecipeBuilder.builder().createRecipe((Object<?>)ItemsAS.CHISEL, AltarType.ATTUNEMENT).setStarlightRequirement(0.4f).setInputs(AltarRecipeGrid.builder().patternLine("     ").patternLine("  GS ").patternLine("  PG ").patternLine(" P   ").patternLine("G    ").key('S', TagsAS.Items.INGOTS_STARMETAL).key('G', (ITag.INamedTag<Item>)Tags.Items.NUGGETS_GOLD).key('P', (ItemLike)BlocksAS.INFUSED_WOOD_PLANKS)).addOutput((ItemLike)ItemsAS.CHISEL).build(registrar);
    }
}
